@[reducible, simp]
def nthDInt (l : List Int) (i : Nat) : Int :=
  l.getD i 0

@[reducible, simp]
def implementation_precond (_l : List Int) : Prop :=
  True

def implementation (l : List Int) (_h : implementation_precond l) : List Int :=
  let every_third_idx := (List.range l.length).filter (fun i => i % 3 = 0)
  let every_third_val := every_third_idx.map (fun i => nthDInt l i)
  let every_third_val_sorted := List.mergeSort (le := (· ≤ ·)) every_third_val
  let result :=
    l.mapIdx (fun i v =>
      if i % 3 = 0 then nthDInt every_third_val_sorted (i / 3)
      else v)
  result

@[reducible, simp]
def implementation_postcond (l : List Int) (result : List Int) (_h : implementation_precond l) : Prop :=
  l.length = result.length ∧
  let every_third_idx := (List.range l.length).filter (fun i => i % 3 = 0)
  let every_third_val_in_result := every_third_idx.map (fun i => nthDInt result i)
  let every_third_val := every_third_idx.map (fun i => nthDInt l i)
  (List.all (List.range l.length) (fun i =>
    decide (i % 3 = 0 ∨ nthDInt l i = nthDInt result i))) ∧
  every_third_val_in_result.Pairwise (fun a b => a ≤ b) ∧
  every_third_val.all (fun x =>
    decide (every_third_val_in_result.count x = every_third_val.count x))

theorem implementation_postcond_satisfied (l : List Int) (h_precond : implementation_precond l) :
    implementation_postcond l (implementation l h_precond) h_precond := by
  sorry

end cleverbench_32

