@[reducible, simp]
def implementation_precond (_l : List Int) : Prop :=
  True

@[simp]
def getD (l : List Int) (i : Nat) : Int :=
  l.getD i 0

def sortedBool (xs : List Int) : Bool :=
  xs.Pairwise (fun a b => a ≤ b)

def implementation (l : List Int) (_h : implementation_precond l) : List Int :=
  let even_idx := (List.range l.length).filter (fun i => i % 2 = 0)
  let even_val := even_idx.map (fun i => getD l i)
  let even_val_sorted := List.mergeSort even_val
  l.mapIdx (fun i v =>
    if i % 2 = 0 then getD even_val_sorted (i / 2) else v)

@[reducible, simp]
def implementation_postcond (l : List Int) (result : List Int) (_h : implementation_precond l) : Bool :=
  let even_idx := (List.range l.length).filter (fun i => i % 2 = 0)
  let even_val_in_result := even_idx.map (fun i => getD result i)
  let even_val := even_idx.map (fun i => getD l i)
  (l.length = result.length) &&
  (List.all (List.range l.length) (fun i =>
    if i % 2 = 0 then true else getD l i = getD result i)) &&
  sortedBool even_val_in_result &&
  even_val.all (fun x => even_val_in_result.count x = even_val.count x)

theorem implementation_postcond_satisfied (l : List Int) (h_precond : implementation_precond l) :
    implementation_postcond l (implementation l h_precond) h_precond = true := by
  sorry

