@[reducible, simp]
def implementation_precond (numbers : List Nat) : Prop :=
  True

def implementation (numbers : List Nat) (h_precond : implementation_precond numbers) : List Nat :=
  let all_odd := numbers.all (fun n => n % 2 = 1)
  if all_odd then []
  else
    let rec find_first_even (i : Nat) : Option (Nat × Nat) :=
      if i ≥ numbers.length then none
      else if numbers[i]! % 2 = 0 then
        let value := numbers[i]!
        let valid :=
          (List.range i).all (fun j => numbers[j]! % 2 = 1 || value < numbers[j]!) &&
          numbers.all (fun n => n % 2 = 1 || value ≤ n)
        if valid then some (value, i) else find_first_even (i + 1)
      else find_first_even (i + 1)
    match find_first_even 0 with
    | some (value, idx) => [value, idx]
    | none => []

def allIdx (n : Nat) (p : Nat → Bool) : Bool :=
  (List.range n).all p

def anyIdx (n : Nat) (p : Nat → Bool) : Bool :=
  (List.range n).any p

def implementation_postcondB (numbers : List Nat) (result : List Nat) : Bool :=
  let allOdd : Bool :=
    numbers.all (fun n => n % 2 = 1)

  let emptyOk : Bool :=
    (decide (result.length = 0)) == allOdd

  let twoLenOk : Bool := decide (result.length = 2)
  let v : Nat := result.getD 0 0
  let idx : Nat := result.getD 1 0

  let existsWitness : Bool :=
    anyIdx numbers.length (fun i =>
      if decide (numbers[i]! % 2 = 0) then
        let idxMatches : Bool := decide (idx = i)
        let vMatches : Bool := decide (v = numbers[i]!)

        let prefixOk : Bool :=
          allIdx i (fun j =>
            decide (numbers[j]! % 2 = 1) || decide (numbers[i]! < numbers[j]!))

        let minimalOk : Bool :=
          allIdx numbers.length (fun k =>
            if decide (numbers[k]! % 2 = 0) then decide (numbers[i]! ≤ numbers[k]!) else true)

        idxMatches && vMatches && prefixOk && minimalOk
      else
        false)

  let twoOk : Bool :=
    twoLenOk == existsWitness

  emptyOk && twoOk

@[reducible, simp]
def implementation_postcond (numbers : List Nat) (result : List Nat)
    (h_precond : implementation_precond numbers) : Prop :=
  (result.length = 0 ↔ ∀ i, i < numbers.length → numbers[i]! % 2 = 1) ∧
    (result.length = 2 ↔
      ∃ i, i < numbers.length ∧
        numbers[i]! % 2 = 0 ∧
        result[0]! = numbers[i]! ∧
        result[1]! = i ∧
        (∀ j, j < numbers.length → j < i → (numbers[j]! % 2 = 1 ∨ numbers[i]! < numbers[j]!)) ∧
        (∀ k, k < numbers.length → numbers[k]! % 2 = 0 → numbers[i]! ≤ numbers[k]!))

@[reducible, simp]
def implementation_postcondQC (numbers : List Nat) (result : List Nat)
    (h_precond : implementation_precond numbers) : Prop :=
  implementation_postcondB numbers result = true

theorem implementation_postcond_satisfied (numbers : List Nat)
    (h_precond : implementation_precond numbers) :
    implementation_postcondQC numbers (implementation numbers h_precond) h_precond := by
  sorry

end cleverbench_67

