namespace cleverbench_104

@[reducible, simp]
def implementation_precond (arr : List Int) : Prop :=
  True

def idxInDigits (digits : List String) (s : String) : Nat :=
  match digits.findIdx? (fun t => t = s) with
  | some i => i
  | none   => 10

def implementation (arr : List Int) (h_precond : implementation_precond (arr)) : List String :=
  let digits := ["One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine"]
  let valid_nums := arr.filter (fun x => 1 ≤ x && x ≤ 9) |>.eraseDup
  let words := valid_nums.map (fun x => digits[x.natAbs - 1]!)
  words.mergeSort (fun a b => idxInDigits digits a ≤ idxInDigits digits b)

def memB [BEq α] (a : α) (xs : List α) : Bool :=
  xs.any (fun x => x == a)

def sortedByDigitIndexB (result : List String) : Bool :=
  let digits : List String :=
    ["One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine"]
  let idxs := result.map (fun s : String => idxInDigits digits s)
  decide (idxs.Pairwise (· ≤ ·))

def implementation_postcondB (arr : List Int) (result : List String) : Bool :=
  let digits : List String :=
    ["One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine"]

  let allInDigits : Bool :=
    result.all (fun s => memB s digits)

  let lenOk : Bool :=
    decide (arr.length ≥ result.length)

  let coverOk : Bool :=
    ([1,2,3,4,5,6,7,8,9] : List Nat).all (fun x =>
      let premise : Bool :=
        memB (Int.ofNat x) arr && decide (1 ≤ x ∧ x ≤ 9)
      let concl : Bool :=
        memB (digits[x - 1]!) result
      (!premise) || concl
    )

  let sortedOk : Bool :=
    sortedByDigitIndexB result

  allInDigits && lenOk && coverOk && sortedOk

@[reducible, simp]
def implementation_postcond (arr : List Int) (result : List String)
    (h_precond : implementation_precond (arr)) : Prop :=
  let digits : List String :=
    ["One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine"]
  (∀ s : String, (s ∈ result → s ∈ digits)) ∧
  (arr.length ≥ result.length) ∧
  (∀ x : Nat, ((x : Int) ∈ arr ∧ 1 ≤ x ∧ x ≤ 9) → (digits[x - 1]! ∈ result)) ∧
  (sortedByDigitIndexB result = true)

theorem implementation_postcond_satisfied (arr : List Int) (h_precond : implementation_precond (arr)) :
    implementation_postcond (arr) (implementation arr h_precond) h_precond := by
  sorry

theorem implementation_postcondB_satisfied (arr : List Int) (h_precond : implementation_precond (arr)) :
    implementation_postcondB arr (implementation arr h_precond) = true := by
  sorry

end cleverbench_104
